import React from "react";
import "../styles/global.css";

const Home = () => {
  return (
    <div className="container">
      <h1>Dobrodošli na Svet Igraonica</h1>
      <p>
        Pronađite savršenu igraonicu za vaše dete, rezervišite termin i uživajte
        - sve na jednom mestu!
      </p>
    </div>
  );
};

export default Home;
